+/// Compute content hash for deduplication
+pub fn content_hash(text: &str) -> [u8; 32] {
+    let mut context = Context::new(&SHA256);
+    context.update(text.as_bytes());
+    let digest = context.finish();
+    
+    let mut hash = [0u8; 32];
+    hash.copy_from_slice(digest.as_ref());
+    hash
